<?php if (!defined('ABSPATH')) exit; get_header(); ?>
<div class="flavor-container py-8"><nav class="flex mb-6 text-sm"><ol class="inline-flex items-center space-x-2"><li><a href="<?php echo home_url('/'); ?>">Inicio</a></li><li><span class="mx-2">/</span></li><li>Eventos</li></ol></nav><h1 class="text-4xl font-bold mb-4">Calendario de Eventos</h1><p class="text-lg text-gray-600 mb-8">Descubre los próximos eventos de la comunidad</p><div class="flex flex-col lg:flex-row gap-8"><aside class="lg:w-1/4"><?php include dirname(__FILE__) . '/filters.php'; ?></aside><main class="lg:w-3/4"><form method="get" class="mb-6 flex gap-2"><input type="text" name="s" placeholder="Buscar eventos..." class="flex-1 px-4 py-3 border rounded-lg"/><button type="submit" class="px-6 py-3 bg-primary text-white rounded-lg">Buscar</button></form><?php $q = new WP_Query(array('post_type' => 'evento', 'posts_per_page' => 12, 'meta_key' => '_fecha_evento', 'orderby' => 'meta_value', 'order' => 'ASC', 'meta_query' => array(array('key' => '_fecha_evento', 'value' => date('Y-m-d'), 'compare' => '>=', 'type' => 'DATE')))); if ($q->have_posts()) : echo '<div class="grid md:grid-cols-2 lg:grid-cols-3 gap-6">'; while ($q->have_posts()) : $q->the_post(); $fecha = get_post_meta(get_the_ID(), '_fecha_evento', true); $hora = get_post_meta(get_the_ID(), '_hora_inicio', true); $ubicacion = get_post_meta(get_the_ID(), '_ubicacion', true); $precio = get_post_meta(get_the_ID(), '_precio_entrada', true); echo '<article class="bg-white rounded-xl shadow-md overflow-hidden hover:shadow-xl transition-all group">'; if (has_post_thumbnail()) : echo '<div class="aspect-video overflow-hidden"><a href="' . get_permalink() . '">'; the_post_thumbnail('medium_large', array('class' => 'w-full h-full object-cover group-hover:scale-105 transition-transform')); echo '</a></div>'; endif; echo '<div class="p-5"><div class="bg-primary text-white rounded-lg p-3 text-center mb-4"><div class="text-3xl font-bold">' . date('d', strtotime($fecha)) . '</div><div class="text-sm uppercase">' . date_i18n('M Y', strtotime($fecha)) . '</div></div><h2 class="text-xl font-bold mb-2 line-clamp-2"><a href="' . get_permalink() . '" class="hover:text-primary">' . get_the_title() . '</a></h2><div class="text-sm text-gray-600 space-y-2 mb-4">'; if ($hora) echo '<p class="flex items-center gap-2"><svg class="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"/></svg>' . esc_html($hora) . '</p>'; if ($ubicacion) echo '<p class="flex items-center gap-2"><svg class="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z"/></svg>' . esc_html($ubicacion) . '</p>'; echo '</div>'; if ($precio) : echo '<p class="text-2xl font-bold text-primary mb-4">' . ($precio == '0' ? 'Gratis' : esc_html($precio) . '€') . '</p>'; endif; echo '<a href="' . get_permalink() . '" class="block text-center px-4 py-2 bg-primary text-white rounded-lg hover:bg-primary-dark">Ver Evento</a></div></article>'; endwhile; echo '</div>'; else : echo '<div class="text-center py-16"><svg class="w-24 h-24 mx-auto text-gray-300 mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z"/></svg><h3 class="text-2xl font-bold">No hay eventos próximos</h3></div>'; endif; wp_reset_postdata(); ?></main></div></div><?php get_footer(); ?>
